[[nodiscard]] auto find_row(const std::uint64_t mtl_pixel_format) -> const Format_caps_row*
{
    const MTL::PixelFormat format = static_cast<MTL::PixelFormat>(mtl_pixel_format);
    for (const Format_caps_row& row : c_format_caps) {
        if (row.format == format) {
            return &row;
        }
    }
    return nullptr;
}

