auto metal_pixel_format_texture_capabilities(
    const std::uint64_t mtl_pixel_format,
    const Gpu_family    family
) noexcept -> std::uint32_t
{
    const Format_caps_row* const row = find_row(mtl_pixel_format);
    if (row == nullptr) {
        return texture_capability_none;
    }
    const int index = static_cast<int>(family);
    if ((index < 0) || (index >= static_cast<int>(Gpu_family::count))) {
        return texture_capability_none;
    }
    return static_cast<std::uint32_t>(row->caps[index]);
}

auto metal_pixel_format_is_known(const std::uint64_t mtl_pixel_format) noexcept -> bool
{
    return find_row(mtl_pixel_format) != nullptr;
}

auto metal_gpu_family_name(const Gpu_family family) noexcept -> const char*
{
    switch (family) {
        case Gpu_family::metal3: return "Metal3";
        case Gpu_family::metal4: return "Metal4";
        case Gpu_family::apple2: return "Apple2";
        case Gpu_family::apple3: return "Apple3";
        case Gpu_family::apple4: return "Apple4";
        case Gpu_family::apple5: return "Apple5";
        case Gpu_family::apple6: return "Apple6";
        case Gpu_family::apple7: return "Apple7";
        case Gpu_family::apple8: return "Apple8";
        case Gpu_family::apple9: return "Apple9";
        case Gpu_family::apple10: return "Apple10";
        case Gpu_family::mac2: return "Mac2";
        default: return "?";
    }
}

auto metal_resolve_gpu_family(MTL::Device* const device) noexcept -> Gpu_family
{
    if (device == nullptr) {
        return Gpu_family::metal3;
    }
    // Prefer the most capable Apple family; its column is a superset of Mac2 on
    // Apple silicon (which reports both). Apple9 covers Apple10 devices too.
    if (device->supportsFamily(MTL::GPUFamilyApple9))  { return Gpu_family::apple9; }
    if (device->supportsFamily(MTL::GPUFamilyApple8))  { return Gpu_family::apple8; }
    if (device->supportsFamily(MTL::GPUFamilyApple7))  { return Gpu_family::apple7; }
    if (device->supportsFamily(MTL::GPUFamilyApple6))  { return Gpu_family::apple6; }
    if (device->supportsFamily(MTL::GPUFamilyApple5))  { return Gpu_family::apple5; }
    if (device->supportsFamily(MTL::GPUFamilyApple4))  { return Gpu_family::apple4; }
    if (device->supportsFamily(MTL::GPUFamilyApple3))  { return Gpu_family::apple3; }
    if (device->supportsFamily(MTL::GPUFamilyApple2))  { return Gpu_family::apple2; }
    if (device->supportsFamily(MTL::GPUFamilyMac2))    { return Gpu_family::mac2;   }
    return Gpu_family::metal3;
}

